// Estructura básica generada por Spring Initializr
package com.paymentchange.customer;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class CustomerApplication {
    public static void main(String[] args) {
        SpringApplication.run(CustomerApplication.class, args);
    }
}

// Entidad Customer con JPA y Lombok
package com.paymentchange.customer.entities;

import jakarta.persistence.*;
import lombok.Data;

@Data
@Entity
public class Customer {
    @Id
    @GeneratedValue(strategy = GenerationType.AUTO)
    private Long id;
    private String name;
    private String phoneNumber;
}

// Repository Interface
package com.paymentchange.customer.repositories;

import com.paymentchange.customer.entities.Customer;
import org.springframework.data.jpa.repository.JpaRepository;

public interface CustomerRepository extends JpaRepository<Customer, Long> {
    // Métodos heredados: save(), findAll(), findById(), delete()
    // No requiere implementación manual
}

package com.paymentchange.customer.controller;

import com.paymentchange.customer.entities.Customer;
import com.paymentchange.customer.repositories.CustomerRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/customer")
public class CustomerRestController {

    @Autowired
    private CustomerRepository customerRepository;

    @GetMapping
    public List<Customer> findAll() {
        return customerRepository.findAll();
    }

    @PostMapping
    public ResponseEntity<Customer> create(@RequestBody Customer input) {
        Customer saved = customerRepository.save(input);
        return ResponseEntity.ok(saved);
    }
}
